export { default as SCollapsible } from './collapsible.vue';
export {
  CollapsibleTrigger as SCollapsibleTrigger,
  CollapsibleContent as SCollapsibleContent
} from '@soybeanjs/headless/collapsible';

export type * from '@soybeanjs/headless/collapsible';
export type * from './types';

import type { CollapsibleRootEmits, CollapsibleRootProps, CollapsibleUi } from '@soybeanjs/headless/collapsible';
import type { ThemeSize } from '@/theme';

/**
 * Properties for the Collapsible component.
 */
export interface CollapsibleProps extends CollapsibleRootProps {
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<CollapsibleUi>;
}

/**
 * Events for the Collapsible component.
 */
export type CollapsibleEmits = CollapsibleRootEmits;

// @unocss-include
import { scv } from '@soybeanjs/cva';

export const collapsibleVariants = scv({
  slots: {
    root: '',
    trigger: '',
    content: [
      'overflow-hidden transition will-change-auto',
      'data-[state=open]:animate-collapsible-down data-[state=closed]:animate-collapsible-up'
    ]
  },
  variants: {
    size: {
      xs: {
        root: 'text-2xs'
      },
      sm: {
        root: 'text-xs'
      },
      md: {
        root: 'text-sm'
      },
      lg: {
        root: 'text-base'
      },
      xl: {
        root: 'text-lg'
      },
      '2xl': {
        root: 'text-xl'
      }
    }
  }
});

import type { ThemeSize } from './types';

export const themeSizeMap: Record<ThemeSize, number> = {
  xs: 12,
  sm: 14,
  md: 16,
  lg: 18,
  xl: 20,
  '2xl': 24
};
export const miniSizeMap: Record<ThemeSize, ThemeSize> = {
  xs: 'xs',
  sm: 'xs',
  md: 'sm',
  lg: 'md',
  xl: 'lg',
  '2xl': 'xl'
};

export const themeSizeRatio = Object.fromEntries(
  Object.entries(themeSizeMap).map(([key, value]) => [key, value / themeSizeMap.md])
) as Record<ThemeSize, number>;
